t.script:

let isEditMode = false;
let originalFormData = {};
/* Issue 12: snapshot original text/skills values at page load for change detection */
let originalExpText = '';
let originalSkillsText = '';

/* Issue 8: fix last-updated timezone */
(function fixExpTimezone() {
    var el = document.getElementById('expLastUpdated');
    if (!el) return;
    var raw = el.textContent.trim().replace(/\u00a0/g,' ');
    if (!raw || raw === 'Never') return;
    try {
        var m = raw.match(/(\d{1,2})\s+(\w+),?\s+(\d{4})\s+at\s+(\d{1,2}):(\d{2})\s*(AM|PM)/i);
        if (m) {
            var months = {jan:0,feb:1,mar:2,apr:3,may:4,jun:5,jul:6,aug:7,sep:8,oct:9,nov:10,dec:11};
            var monIdx = months[m[2].toLowerCase().substring(0,3)];
            var hr = parseInt(m[4],10);
            var isPM = m[6].toUpperCase()==='PM';
            if (isPM && hr < 12) hr += 12;
            if (!isPM && hr === 12) hr = 0;
            var dt = new Date(Date.UTC(parseInt(m[3],10), monIdx, parseInt(m[1],10), hr, parseInt(m[5],10)));
            if (!isNaN(dt.getTime())) {
                el.textContent = dt.toLocaleString(undefined,{day:'2-digit',month:'short',year:'numeric',hour:'2-digit',minute:'2-digit',hour12:true});
            }
        }
    } catch(e) {}
})();

document.addEventListener('DOMContentLoaded', function () {
    /* snapshot originals for change detection (Issue 12) */
    originalExpText = (document.getElementById('experienceText').value || '').trim();
    originalSkillsText = (document.getElementById('skillsInput').value || '').trim();

    updateSkillsDisplay();
    updateWordCount();
    calculateExperience();

    /* Issue 13: ensure resume file input is disabled on load */
    document.querySelectorAll('.exp-file-input').forEach(fi => fi.setAttribute('disabled','disabled'));
});

/* Issue 9: show badge only when count > 0 */
function updateSkillsDisplay() {
    const skillsInput = document.getElementById('skillsInput');
    const skillsBadges = document.getElementById('skillsBadges');
    const skillsCountEl = document.getElementById('skillsCount');
    if (skillsInput && skillsInput.value && skillsInput.value.trim()) {
        const skills = skillsInput.value.split(',').map(s => s.trim()).filter(s => s);
        skillsBadges.innerHTML = '';
        skills.forEach(skill => {
            const badge = document.createElement('span');
            badge.className = 'badge bg-primary me-1 mb-1';
            badge.textContent = skill;
            skillsBadges.appendChild(badge);
        });
        if (skills.length > 0) {
            skillsCountEl.textContent = skills.length + ' Skills';
            skillsCountEl.style.display = '';
        } else {
            skillsCountEl.style.display = 'none';
        }
    } else {
        skillsBadges.innerHTML = '<span class="text-muted small">No skills added yet</span>';
        skillsCountEl.style.display = 'none';
    }
}

/* Issue 9: show word count only when > 0 */
function updateWordCount() {
    const experienceText = document.getElementById('experienceText');
    const wrapEl = document.getElementById('experienceWordCountWrap');
    const countEl = document.getElementById('experienceWordCount');
    if (experienceText) {
        const wordCount = experienceText.value.trim().split(/\s+/).filter(w => w.length > 0).length;
        if (wordCount > 0) {
            countEl.textContent = wordCount;
            wrapEl.style.display = '';
        } else {
            wrapEl.style.display = 'none';
        }
    }
}

/* Issue 9: show years badge only when value > 0 */
function calculateExperience() {
    const experienceText = document.getElementById('experienceText');
    const yearsEl = document.getElementById('experienceYears');
    if (!experienceText) return;
    const text = experienceText.value.toLowerCase();
    const yearMatches = text.match(/(\d+)\s*(years?|yrs?)/g);
    if (yearMatches) {
        const years = yearMatches.map(m => parseInt(m.match(/\d+/)[0]));
        const maxYears = Math.max(...years);
        if (maxYears > 0) {
            yearsEl.textContent = maxYears + ' Years';
            yearsEl.style.display = '';
            return;
        }
    }
    yearsEl.style.display = 'none';
}

/* Issue 10: change Edit button style when in edit mode */
function enableFullEdit() {
    isEditMode = true;
    storeOriginalFormData();
    const inputs = document.querySelectorAll('#experienceForm input, #experienceForm textarea');
    inputs.forEach(input => {
        if (input.type !== 'hidden') {
            input.removeAttribute('readonly');
            input.removeAttribute('disabled');
        }
    });
    /* Issue 13: enable file inputs in edit mode */
    document.querySelectorAll('#experienceForm .exp-file-input').forEach(fi => fi.removeAttribute('disabled'));

    document.getElementById('formActions').style.display = 'block';
    document.getElementById('viewActions').style.display = 'none';

    /* Issue 10: change button appearance */
    var editBtn = document.getElementById('expEditBtn');
    if (editBtn) {
        editBtn.classList.remove('btn-outline-primary');
        editBtn.classList.add('btn-primary', 'edit-active');
        editBtn.innerHTML = '<i class="fa fa-pencil me-1"></i>Editing Mode ON';
    }

    const disc = document.getElementById('expDisclaimer');
    if (disc) disc.checked = false;
    const btn = document.getElementById('expSaveBtn');
    if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }
    document.getElementById('experienceText').addEventListener('input', function () {
        updateWordCount();
        calculateExperience();
    });
    document.getElementById('skillsInput').addEventListener('input', updateSkillsDisplay);
}

function toggleExpSaveBtn() {
    const checked = document.getElementById('expDisclaimer').checked;
    const btn = document.getElementById('expSaveBtn');
    btn.disabled = !checked;
    btn.style.opacity = checked ? '1' : '0.6';
}

function storeOriginalFormData() {
    const form = document.getElementById('experienceForm');
    const formData = new FormData(form);
    originalFormData = {};
    for (let [key, value] of formData.entries()) {
        originalFormData[key] = value;
    }
}

function cancelEdit() {
    for (let [key, value] of Object.entries(originalFormData)) {
        const input = document.querySelector(`[name="${key}"]`);
        if (input && input.type !== 'hidden' && input.type !== 'file') {
            input.value = value;
        }
    }
    disableEditMode();
    updateSkillsDisplay();
    updateWordCount();
    calculateExperience();
    showMessage('Changes cancelled.', 'info');
}

function disableEditMode() {
    isEditMode = false;
    const inputs = document.querySelectorAll('#experienceForm input, #experienceForm textarea');
    inputs.forEach(input => {
        if (input.type !== 'hidden' && input.type !== 'file') {
            input.setAttribute('readonly', 'readonly');
        }
    });
    /* Issue 13: disable file inputs when leaving edit mode */
    document.querySelectorAll('#experienceForm .exp-file-input').forEach(fi => {
        fi.setAttribute('disabled', 'disabled');
        fi.value = '';
    });

    document.getElementById('formActions').style.display = 'none';
    document.getElementById('viewActions').style.display = 'block';

    /* Issue 10: restore button appearance */
    var editBtn = document.getElementById('expEditBtn');
    if (editBtn) {
        editBtn.classList.remove('btn-primary', 'edit-active');
        editBtn.classList.add('btn-outline-primary');
        editBtn.innerHTML = '<i class="fa fa-edit me-1"></i>Edit Experience &amp; Skills';
    }

    const disc = document.getElementById('expDisclaimer');
    if (disc) disc.checked = false;
    const btn = document.getElementById('expSaveBtn');
    if (btn) { btn.disabled = true; btn.style.opacity = '0.6'; }
}

document.getElementById('experienceForm').addEventListener('submit', function (e) {
    e.preventDefault();
    const disc = document.getElementById('expDisclaimer');
    if (disc && !disc.checked) {
        showMessage('Please read and accept the Employee Disclaimer before saving.', 'error');
        return;
    }

    /* Issue 12: detect if anything actually changed */
    const currentExpText = (document.getElementById('experienceText').value || '').trim();
    const currentSkillsText = (document.getElementById('skillsInput').value || '').trim();
    const resumeInput = document.getElementById('resumeFileInput');
    const hasFileChange = resumeInput && resumeInput.files && resumeInput.files.length > 0;

    if (currentExpText === originalExpText && currentSkillsText === originalSkillsText && !hasFileChange) {
        showMessage('No changes detected. Your experience data is already up to date.', 'info');
        return;
    }

    /* Issue 11: show upload overlay for large files */
    const hasLargeFile = hasFileChange && resumeInput.files[0].size > 1 * 1024 * 1024; /* >1MB */
    var overlay = document.getElementById('uploadProgressOverlay');
    if (hasLargeFile || hasFileChange) {
        overlay.style.display = 'flex';
    }

    const formData = new FormData(this);
    fetch('/my/employee/experience', {
        method: 'POST',
        body: formData
    })
    .then(response => {
        if (overlay) overlay.style.display = 'none';
        return response.json();
    })
    .then(data => {
        if (data.success) {
            /* Update snapshots so re-save correctly detects no change */
            originalExpText = currentExpText;
            originalSkillsText = currentSkillsText;
            showMessage('Experience and skills updated successfully!', 'success');
            disableEditMode();
        } else {
            showMessage('Error: ' + (data.error || 'Unknown error'), 'error');
        }
    })
    .catch(error => {
        if (overlay) overlay.style.display = 'none';
        console.error('Error:', error);
        showMessage('Network error. Please try again.', 'error');
    });
});

function showMessage(text, type) {
    const messageContainer = document.getElementById('messageContainer');
    const successMsg = document.getElementById('successMessage');
    const errorMsg = document.getElementById('errorMessage');
    successMsg.style.display = 'none';
    errorMsg.style.display = 'none';
    successMsg.classList.remove('show');
    errorMsg.classList.remove('show');
    if (type === 'success') {
        document.getElementById('successText').textContent = text;
        successMsg.style.display = 'block';
        successMsg.classList.add('show');
    } else if (type === 'info') {
        document.getElementById('successText').textContent = text;
        successMsg.style.display = 'block';
        successMsg.classList.add('show');
    } else {
        document.getElementById('errorText').textContent = text;
        errorMsg.style.display = 'block';
        errorMsg.classList.add('show');
    }
    messageContainer.style.display = 'block';
    messageContainer.scrollIntoView({behavior: 'smooth'});
    setTimeout(() => {
        successMsg.classList.remove('show');
        errorMsg.classList.remove('show');
    }, 5000);
}
